#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor gemm_relu_divide_impl_npu(const at::Tensor& x,
                                     const at::Tensor& w,
                                     const at::Tensor& b,
                                     const at::Tensor& divisor) {
    TORCH_CHECK(x.dtype() == at::kFloat && w.dtype() == at::kFloat &&
                b.dtype() == at::kFloat && divisor.dtype() == at::kFloat,
                "All tensors must be float32.");
    TORCH_CHECK(x.dim() == 2 && w.dim() == 2 && b.dim() == 1,
                "Shapes: x [M,K], w [N,K], b [N]");
    TORCH_CHECK(divisor.numel() == 1, "divisor must be a scalar tensor.");

    auto M = x.size(0);
    auto K = x.size(1);
    TORCH_CHECK(w.size(1) == K, "w shape mismatch with x.");
    auto N = w.size(0);
    TORCH_CHECK(b.size(0) == N, "b size mismatch with w.");

    at::Tensor result = at::empty({M, N}, x.options());
    EXEC_NPU_CMD(aclnnGemmReluDivideCustom, x, w, b, divisor, result);
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("gemm_relu_divide_custom", &gemm_relu_divide_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("gemm_relu_divide_custom", &gemm_relu_divide_impl_npu,
          "Fused GEMM + ReLU + Divide (GemmReluDivideCustom on NPU)");
}
